// Define cache-heavy apps to clean
const cacheHeavyApps = [
  { package: 'com.instagram.android', name: 'Instagram' },
  { package: 'com.facebook.katana', name: 'Facebook' },
  { package: 'com.google.android.youtube', name: 'YouTube' },
  { package: 'com.android.chrome', name: 'Chrome' },
  { package: 'com.whatsapp', name: 'WhatsApp' },
  { package: 'org.telegram.messenger', name: 'Telegram' },
  { package: 'com.twitter.android', name: 'Twitter' },
  { package: 'com.snapchat.android', name: 'Snapchat' },
  { package: 'com.google.android.apps.photos', name: 'Google Photos' },
  { package: 'com.spotify.music', name: 'Spotify' }
];

return cacheHeavyApps.map(app => ({ json: app }));

// Check if cache clear was successful
const output = $input.first().json.stdout;
const appName = $('Process Apps One by One').item.json.name;
const packageName = $('Process Apps One by One').item.json.package;

const success = !output.includes('App not found') && !output.includes('error');

return [{
  json: {
    app_name: appName,
    package_name: packageName,
    cache_cleared: success,
    output: output,
    timestamp: new Date().toISOString()
  }
}];

// Calculate cleanup statistics
const allResults = $('Check Clear Result').all();
const totalApps = allResults.length;
const successfulClears = allResults.filter(item => item.json.cache_cleared).length;
const failedClears = totalApps - successfulClears;

const storageInfo = $('Check Available Storage').first().json.stdout.trim();
const storageUsage = $('Check Storage Usage').first().json.stdout;

const successApps = allResults
  .filter(item => item.json.cache_cleared)
  .map(item => `✅ ${item.json.app_name}`)
  .join('\n');

const failedApps = allResults
  .filter(item => !item.json.cache_cleared)
  .map(item => `❌ ${item.json.app_name}`)
  .join('\n');

return [{
  json: {
    total_apps: totalApps,
    successful_clears: successfulClears,
    failed_clears: failedClears,
    available_storage: storageInfo,
    storage_usage_top: storageUsage.split('\n').slice(0, 5).join('\n'),
    success_apps: successApps,
    failed_apps: failedApps,
    cleanup_time: new Date().toLocaleString()
  }
}];

